-- Auto-generated: inserts new recipes into public.recipes.
-- Idempotent: skips names that already exist; ids continue after MAX(id).
-- image_url left blank — the app's image resolver fills it automatically.
-- Run this in the Supabase SQL editor.

with new_recipes (name, ingredients, time_minutes, calories, difficulty, diet, tags, category, steps) as (
  values
    ('Paneer Tikka Masala', 'paneer, onion, tomato, ginger, garlic, cumin, turmeric, red chilli powder, coriander powder, garam masala, salt, oil, coriander leaves', 30, 300, 'easy', 'veg', 'comfort', 'north-indian', 'Heat 2 tbsp oil in a heavy pan; add 1 large finely chopped onion and saute 5-6 minutes until golden brown; Add 1 tbsp ginger-garlic paste and cook 1 minute until the raw smell disappears; Add 2 pureed tomatoes (or 3 tbsp tomato paste) and cook 4-5 minutes until the oil separates at the edges; Stir in 1/2 tsp turmeric, 1 tsp red chilli powder, 1 tsp coriander powder and 3/4 tsp salt; cook 1 minute; Add the paneer with about 3/4 cup water, cover and simmer 10-12 minutes until cooked through and the gravy thickens; Sprinkle 1/2 tsp garam masala, swirl in 2 tbsp cream or whisked yogurt, and finish with chopped coriander; serve hot'),
    ('Paneer Butter Masala', 'paneer, onion, tomato, ginger, garlic, cumin, turmeric, red chilli powder, coriander powder, garam masala, salt, oil, coriander leaves', 25, 260, 'easy', 'veg', 'comfort', 'north-indian', 'Heat 2 tbsp oil in a heavy pan; add 1 large finely chopped onion and saute 5-6 minutes until golden brown; Add 1 tbsp ginger-garlic paste and cook 1 minute until the raw smell disappears; Add 2 pureed tomatoes (or 3 tbsp tomato paste) and cook 4-5 minutes until the oil separates at the edges; Stir in 1/2 tsp turmeric, 1 tsp red chilli powder, 1 tsp coriander powder and 3/4 tsp salt; cook 1 minute; Add the paneer with about 3/4 cup water, cover and simmer 10-12 minutes until cooked through and the gravy thickens; Sprinkle 1/2 tsp garam masala, swirl in 2 tbsp cream or whisked yogurt, and finish with chopped coriander; serve hot'),
