    ('Medu Vada', 'urad dal, gram flour, rice flour, green chilli, ginger, turmeric, salt, oil, coriander leaves', 30, 200, 'easy', 'veg', 'comfort', 'south-indian', 'Mix the urad dal with 1 finely chopped onion, 1 green chilli, 1/2 tsp turmeric, 1/2 tsp chilli powder and salt; bind well; Shape into even portions, or dip in a thick gram-flour batter; Heat oil to 170-180C and fry in small batches 3-4 minutes until golden and crisp; Drain on paper towels; serve hot with green chutney'),
    ('Sambar Vada', 'lentil and sambar, gram flour, rice flour, green chilli, ginger, turmeric, salt, oil, coriander leaves', 25, 200, 'easy', 'veg', 'comfort', 'south-indian', 'Mix the lentil and sambar with 1 finely chopped onion, 1 green chilli, 1/2 tsp turmeric, 1/2 tsp chilli powder and salt; bind well; Shape into even portions, or dip in a thick gram-flour batter; Heat oil to 170-180C and fry in small batches 3-4 minutes until golden and crisp; Drain on paper towels; serve hot with green chutney'),
    ('Dahi Vada', 'yogurt, gram flour, rice flour, green chilli, ginger, turmeric, salt, oil, coriander leaves', 25, 240, 'easy', 'veg', 'comfort', 'south-indian', 'Mix the yogurt with 1 finely chopped onion, 1 green chilli, 1/2 tsp turmeric, 1/2 tsp chilli powder and salt; bind well; Shape into even portions, or dip in a thick gram-flour batter; Heat oil to 170-180C and fry in small batches 3-4 minutes until golden and crisp; Drain on paper towels; serve hot with green chutney'),
    ('Uttapam', 'onion and tomato, rice, urad dal, salt, oil, mustard seeds, curry leaves', 25, 200, 'easy', 'veg', 'healthy', 'south-indian', 'Soak 2 cups rice with 1/2 cup urad dal for 4-6 hours; grind to a smooth batter and ferment overnight; Mix in the onion and tomato with 3/4 tsp salt and a little water to a pourable (or idli) consistency; Heat a greased griddle (or idli steamer); pour and spread thin, or steam 10-12 minutes; Cook until golden and crisp, or fluffy and set; Serve hot with coconut chutney and sambar'),
    ('Pongal', 'rice and moong dal, rice, urad dal, salt, oil, mustard seeds, curry leaves', 25, 240, 'easy', 'veg', 'healthy', 'south-indian', 'Soak 2 cups rice with 1/2 cup urad dal for 4-6 hours; grind to a smooth batter and ferment overnight; Mix in the rice and moong dal with 3/4 tsp salt and a little water to a pourable (or idli) consistency; Heat a greased griddle (or idli steamer); pour and spread thin, or steam 10-12 minutes; Cook until golden and crisp, or fluffy and set; Serve hot with coconut chutney and sambar'),
    ('Upma', 'semolina, rice, urad dal, salt, oil, mustard seeds, curry leaves', 30, 280, 'easy', 'veg', 'healthy', 'south-indian', 'Soak 2 cups rice with 1/2 cup urad dal for 4-6 hours; grind to a smooth batter and ferment overnight; Mix in the semolina with 3/4 tsp salt and a little water to a pourable (or idli) consistency; Heat a greased griddle (or idli steamer); pour and spread thin, or steam 10-12 minutes; Cook until golden and crisp, or fluffy and set; Serve hot with coconut chutney and sambar'),
    ('Rava Kesari', 'semolina, sugar, milk, ghee, cardamom, chopped nuts', 25, 280, 'easy', 'veg', 'comfort', 'sweets', 'Cook the semolina with 2 cups full-fat milk and 1 tbsp ghee on low heat, stirring often so it doesn''t catch; When it thickens, add 1/2 cup sugar and 1/4 tsp cardamom powder; keep stirring 8-10 minutes; Cook until it leaves the sides of the pan and turns glossy; Garnish with 2 tbsp chopped nuts; serve warm or chilled'),
    ('Pesarattu', 'green gram, rice, urad dal, salt, oil, mustard seeds, curry leaves', 20, 240, 'easy', 'veg', 'healthy', 'south-indian', 'Soak 2 cups rice with 1/2 cup urad dal for 4-6 hours; grind to a smooth batter and ferment overnight; Mix in the green gram with 3/4 tsp salt and a little water to a pourable (or idli) consistency; Heat a greased griddle (or idli steamer); pour and spread thin, or steam 10-12 minutes; Cook until golden and crisp, or fluffy and set; Serve hot with coconut chutney and sambar'),
    ('Appam', 'rice and coconut, rice, urad dal, salt, oil, mustard seeds, curry leaves', 20, 280, 'easy', 'veg', 'healthy', 'south-indian', 'Soak 2 cups rice with 1/2 cup urad dal for 4-6 hours; grind to a smooth batter and ferment overnight; Mix in the rice and coconut with 3/4 tsp salt and a little water to a pourable (or idli) consistency; Heat a greased griddle (or idli steamer); pour and spread thin, or steam 10-12 minutes; Cook until golden and crisp, or fluffy and set; Serve hot with coconut chutney and sambar'),
    ('Idiyappam', 'rice flour, rice, urad dal, salt, oil, mustard seeds, curry leaves', 30, 200, 'easy', 'veg', 'healthy', 'south-indian', 'Soak 2 cups rice with 1/2 cup urad dal for 4-6 hours; grind to a smooth batter and ferment overnight; Mix in the rice flour with 3/4 tsp salt and a little water to a pourable (or idli) consistency; Heat a greased griddle (or idli steamer); pour and spread thin, or steam 10-12 minutes; Cook until golden and crisp, or fluffy and set; Serve hot with coconut chutney and sambar'),
    ('Sambar', 'lentils and vegetables, ghee, cumin, garlic, dry red chilli, asafoetida, turmeric, salt, coriander leaves', 30, 260, 'easy', 'veg', 'comfort', 'south-indian', 'Rinse 1 cup lentils and vegetables and pressure cook with 3 cups water, 1/2 tsp turmeric and 3/4 tsp salt for 3-4 whistles until soft; Whisk the dal smooth and add hot water to reach a pourable consistency; keep on a low simmer; For the tempering, heat 2 tbsp ghee and add 1 tsp cumin, 4 sliced garlic cloves, 2 dry red chillies and a pinch of asafoetida; fry until golden; Pour the sizzling tempering over the dal; Simmer 5 minutes, finish with chopped coriander and a squeeze of lemon; serve hot with rice or roti'),
    ('Rasam', 'tamarind and tomato, ghee, cumin, garlic, dry red chilli, asafoetida, turmeric, salt, coriander leaves', 35, 260, 'easy', 'veg', 'comfort', 'south-indian', 'Rinse 1 cup tamarind and tomato and pressure cook with 3 cups water, 1/2 tsp turmeric and 3/4 tsp salt for 3-4 whistles until soft; Whisk the dal smooth and add hot water to reach a pourable consistency; keep on a low simmer; For the tempering, heat 2 tbsp ghee and add 1 tsp cumin, 4 sliced garlic cloves, 2 dry red chillies and a pinch of asafoetida; fry until golden; Pour the sizzling tempering over the dal; Simmer 5 minutes, finish with chopped coriander and a squeeze of lemon; serve hot with rice or roti'),
    ('Tomato Rasam', 'tomato, ghee, cumin, garlic, dry red chilli, asafoetida, turmeric, salt, coriander leaves', 25, 180, 'easy', 'veg', 'comfort', 'south-indian', 'Rinse 1 cup tomato and pressure cook with 3 cups water, 1/2 tsp turmeric and 3/4 tsp salt for 3-4 whistles until soft; Whisk the dal smooth and add hot water to reach a pourable consistency; keep on a low simmer; For the tempering, heat 2 tbsp ghee and add 1 tsp cumin, 4 sliced garlic cloves, 2 dry red chillies and a pinch of asafoetida; fry until golden; Pour the sizzling tempering over the dal; Simmer 5 minutes, finish with chopped coriander and a squeeze of lemon; serve hot with rice or roti'),
    ('Pepper Rasam', 'black pepper, ghee, cumin, garlic, dry red chilli, asafoetida, turmeric, salt, coriander leaves', 35, 220, 'easy', 'veg', 'comfort', 'south-indian', 'Rinse 1 cup black pepper and pressure cook with 3 cups water, 1/2 tsp turmeric and 3/4 tsp salt for 3-4 whistles until soft; Whisk the dal smooth and add hot water to reach a pourable consistency; keep on a low simmer; For the tempering, heat 2 tbsp ghee and add 1 tsp cumin, 4 sliced garlic cloves, 2 dry red chillies and a pinch of asafoetida; fry until golden; Pour the sizzling tempering over the dal; Simmer 5 minutes, finish with chopped coriander and a squeeze of lemon; serve hot with rice or roti'),
    ('Avial', 'mixed vegetables and coconut, onion, tomato, ginger, garlic, cumin, turmeric, red chilli powder, coriander powder, garam masala, salt, oil, coriander leaves', 25, 220, 'easy', 'veg', 'comfort', 'south-indian', 'Heat 2 tbsp oil in a heavy pan; add 1 large finely chopped onion and saute 5-6 minutes until golden brown; Add 1 tbsp ginger-garlic paste and cook 1 minute until the raw smell disappears; Add 2 pureed tomatoes (or 3 tbsp tomato paste) and cook 4-5 minutes until the oil separates at the edges; Stir in 1/2 tsp turmeric, 1 tsp red chilli powder, 1 tsp coriander powder and 3/4 tsp salt; cook 1 minute; Add the mixed vegetables and coconut with about 3/4 cup water, cover and simmer 10-12 minutes until cooked through and the gravy thickens; Sprinkle 1/2 tsp garam masala, swirl in 2 tbsp cream or whisked yogurt, and finish with chopped coriander; serve hot'),
    ('Vegetable Korma', 'mixed vegetables and coconut, onion, tomato, ginger, garlic, cumin, turmeric, red chilli powder, coriander powder, garam masala, salt, oil, coriander leaves', 25, 180, 'easy', 'veg', 'comfort', 'south-indian', 'Heat 2 tbsp oil in a heavy pan; add 1 large finely chopped onion and saute 5-6 minutes until golden brown; Add 1 tbsp ginger-garlic paste and cook 1 minute until the raw smell disappears; Add 2 pureed tomatoes (or 3 tbsp tomato paste) and cook 4-5 minutes until the oil separates at the edges; Stir in 1/2 tsp turmeric, 1 tsp red chilli powder, 1 tsp coriander powder and 3/4 tsp salt; cook 1 minute; Add the mixed vegetables and coconut with about 3/4 cup water, cover and simmer 10-12 minutes until cooked through and the gravy thickens; Sprinkle 1/2 tsp garam masala, swirl in 2 tbsp cream or whisked yogurt, and finish with chopped coriander; serve hot'),
